  margin-top: 0.15rem;
  padding-left: 5.2em;
}

.links__description::before {
  content: '# ';
}

/* ── Footer ──────────────────────────────────────────────────────── */

.footer {
  margin-top: auto;
  padding-top: 2rem;
  padding-bottom: 1rem;
  text-align: center;
  max-width: var(--page-max-width);
  width: 100%;
  border-top: 1px solid var(--link-border);
}

.footer__link {
  font-size: 0.65rem;
