  // Check :root block
  const hasRoot = css.includes(':root');

  // Check tokens
  const missingTokens = tokens.filter(tok => !css.includes(tok));

  // Check selectors
  const missingSel = required_selectors.filter(s => !css.includes(s));

  // Check no hardcoded colors outside :root (simplified check)

